#include <iostream>
#include <fstream>
#include <string>
#include <sstream>

int main() {
    std::string filename, target_word;
    int word_count = 0;

    // Prompt the user for the filename
    std::cout << "Enter the name of the text file: ";
    std::cin >> filename;

    // Prompt the user for the target word
    std::cout << "Enter the word you want to search for: ";
    std::cin >> target_word;

    // Open the file
    std::ifstream file(filename);

    // Check if the file was opened successfully
    if (!file.is_open()) {
        std::cerr << "Error: Could not open file '" << filename << "'" << std::endl;
        return 1;
    }

    // Read the file line by line
    std::string line;
    while (std::getline(file, line)) {
        std::istringstream iss(line);  // Create a stream from the current line
        std::string word;

        // Extract words from the line
        while (iss >> word) {
            // Convert the word to lowercase for case-insensitive comparison
            std::transform(word.begin(), word.end(), word.begin(),
                           [](unsigned char c){ return std::tolower(c); });

            // Compare the word with the target word
            if (word == target_word) {
                word_count++;
            }
        }
    }

    // Close the file
    file.close();

    // Output the result
    std::cout << "The word '" << target_word << "' appears " << word_count << " times in the file." << std::endl;

    return 0;
}
```

### Explanation:
1. **Input Handling**: 
   - The program first prompts the user to enter the filename and the word they want to search for.

2. **File Reading**:
